local HOWLING_ABYSS = ""
local SUMMONER_RIFT_STANDARD = ""
local SUMMONER_RIFT_DRAGON_INFERNAL = ""
local SUMMONER_RIFT_DRAGON_MOUNTAIN = ""
local SUMMONER_RIFT_DRAGON_OCEAN = ""
local SUMMONER_RIFT_HEIGHT_MAP_DATA = ""
local SUMMONER_RIFT_REGION_MAP_DATA = ""
local ARENA_2v2v2v2_FEATURED_MODE = ""

local abs = math.abs
local min = math.min
local floor = math.floor
local huge = 10 ^ 308
local loaded = false
local lz = require("LZ-Lua")

-- Class constructor

local Class = function(...)
    local cls = {}
    cls.__index = cls
    function cls:New(...)
        local instance = setmetatable({}, cls)
        cls.__init(instance, ...)
        return instance
    end
    cls.__call = function(_, ...) return cls:New(...) end
    return setmetatable(cls, {__call = cls.__call})
end

-- Utils

local function ClosestOnCell(cx, cy, px, py, len)
    if abs(cx - px) <= len then
        local sign = py >= cy and 1 or -1
        return px, cy + sign * len end
    if abs(cy - py) <= len then
        local sign = px >= cx and 1 or -1
        return cx + sign * len, py end
    return px > cx and cx + len or cx - len,
        py > cy and cy + len or cy - len
end

local function DistanceSquared(ax, ay, bx, by)
    local dx, dy = bx - ax, by - ay
    return dx * dx + dy * dy
end

-- Map library

local Regions = {
    "BLUE_BASE",
    "BOT_LANE",
    "BOT_BLUE_JUNGLE",
    "BOT_RED_JUNGLE",
    "BOT_RIVER",
    "MID_LANE",
    "TOP_RIVER",
    "TOP_RED_JUNGLE",
    "TOP_BLUE_JUNGLE",
    "TOP_LANE",
    "RED_BASE"
}

_G.UNKNOWN_MAP_ID = -1
_G.HOWLING_ABYSS_MAP_ID = 0
_G.SUMMONER_RIFT_STANDARD_MAP_ID = 1
_G.SUMMONER_RIFT_DRAGON_INFERNAL_MAP_ID = 2
_G.SUMMONER_RIFT_DRAGON_MOUNTAIN_MAP_ID = 3
_G.SUMMONER_RIFT_DRAGON_OCEAN_MAP_ID = 4
_G.ARENA_2v2v2v2_FEATURED_MODE_MAP_ID = 5

local MapLibrary = Class()

function MapLibrary:__init()
    if loaded then return end
    self.id = _G.UNKNOWN_MAP_ID
    self.dirX = { -1, 0, 1, 0 }
    self.dirY = { 0, 1, 0, -1 }
    self:InitSelector()
    self.heights = nil
    self.regions = nil
    self.map = nil
    self.limitX = 0
    self.limitY = 0
    self.offsetX = 0
    self.offsetY = 0
    self.size = 50
    self.bushes = {}
    self.river = {}
    self.walls = {}
    loaded = true
end

function MapLibrary:InitSelector()
    self.selector = {}
    self.selector["BUSHES"] = function(x, y)
        return self:IsBush(x, y, true) end
    self.selector["RIVER"] = function(x, y)
        return self:IsRiver(x, y, true) end
    self.selector["WALLS"] = function(x, y)
        return self:IsWall(x, y, true) end
end

-- Map ID getter and loaders

function MapLibrary:GetLoadedMapId()
    return self.id
end

function MapLibrary:LoadHeightMap()
    if self.id < 1 then return false end
    if self.id == 5 then return false end
    if self.heights then return false end
    local data = lz.DecompressFromBase64(
        SUMMONER_RIFT_HEIGHT_MAP_DATA)
    self.heights = loadstring(data)()
    return true
end

function MapLibrary:LoadRegionMap()
    if self.id < 1 then return false end
    if self.id == 5 then return false end
    if self.regions then return false end
    local data = lz.DecompressFromBase64(
        SUMMONER_RIFT_REGION_MAP_DATA)
    self.regions = loadstring(data)()
    return true
end

function MapLibrary:ReloadMap(id)
    local data = lz.DecompressFromBase64(({
        [0] = HOWLING_ABYSS,
        [1] = SUMMONER_RIFT_STANDARD,
        [2] = SUMMONER_RIFT_DRAGON_INFERNAL,
        [3] = SUMMONER_RIFT_DRAGON_MOUNTAIN,
        [4] = SUMMONER_RIFT_DRAGON_OCEAN,
        [5] = ARENA_2v2v2v2_FEATURED_MODE
    })[id or _G.HOWLING_ABYSS_MAP_ID])
    self.map = loadstring(data)()
    self.id = id or _G.HOWLING_ABYSS_MAP_ID
    self.bushes = self.map["BUSHES"] or {}
    self.river = self.map["RIVER"] or {}
    self.walls = self.map["WALLS"] or {}
    local lx = {[0] = 243, [5] = 273}
    local ly = {[0] = 234, [5] = 273}
    local ox = {[0] = 504, [5] = 2150}
    local oy = {[0] = 369, [5] = 2150}
    self.limitX = lx[self.id] or 294
    self.limitY = ly[self.id] or 294
    self.offsetX = ox[self.id] or 1
    self.offsetY = oy[self.id] or 83
end

-- Converters

function MapLibrary:CellToWorld(x, y, skip)
    if skip then return x, y end
    local size = self.size or 50
    local tx = x * size + self.offsetX
    local ty = y * size + self.offsetY
    return tx + size / 2, ty + size / 2
end

function MapLibrary:_WorldToCell(x, y)
    local size = self.size or 50
    local tx = (x - self.offsetX) / size
    local ty = (y - self.offsetY) / size
    return tx, ty
end

function MapLibrary:WorldToCell(x, y, skip)
    if skip then return x, y end
    local size = self.size or 50
    local tx = (x - self.offsetX) / size
    local ty = (y - self.offsetY) / size
    return floor(tx), floor(ty)
end

-- Breadth first search

function MapLibrary:BFS(x, y, range, key, closest)
    local finish, queue, visits = false, {}, {}
    local best, id, result = huge, -1, {}
    local tx, ty = self:WorldToCell(x, y)
    table.insert(queue, {x = tx, y = ty})
    local dx, dy = self.dirX, self.dirY
    local size, inside = self.size / 2
    visits[tx] = {[ty] = true}
    local function AddToQueue(index, px, py)
        if inside == false then return end
        if finish and closest then return false end
        local ax, ay = px + dx[index], py + dy[index]
        local visited = visits[ax] and visits[ax][ay]
        if visited and visited == true then return end
        if not visits[ax] then visits[ax] = {} end
        table.insert(queue, {x = ax, y = ay})
        visits[ax][ay] = true
    end
    while #queue > 0 do
        local point = queue[1]
        table.remove(queue, 1)
        local px, py = point.x, point.y
        local cx, cy = self:CellToWorld(px, py)
        local fx, fy = ClosestOnCell(cx, cy, x, y, size)
        if px == tx and py == ty then fx, fy = x, y end
        local dist = DistanceSquared(fx, fy, x, y)
        inside = range > 0 and dist <= range ^ 2
        if inside == true and (closest == true and
            dist <= best or closest == false) and
            self.selector[key](px, py) == true then
            best, id, finish = dist, id + 1, true
            result[id + 1] = {x1 = cx, y1 = cy,
                x2 = fx, y2 = fy, dist = dist} end
        for i = 1, 4 do AddToQueue(i, px, py) end
    end
    return closest and result[#result] or result
end

function MapLibrary:FindClosestBush(x, y, range)
    local range = range and min(range, 1000) or 1000
    return self:BFS(x, y, range, "BUSHES", true)
end

function MapLibrary:FindClosestRiver(x, y, range)
    local range = range and min(range, 1000) or 1000
    return self:BFS(x, y, range, "RIVER", true)
end

function MapLibrary:FindClosestWall(x, y, range)
    local range = range and min(range, 1000) or 1000
    return self:BFS(x, y, range, "WALLS", true)
end

function MapLibrary:FindBushCells(x, y, range)
    local range = range and min(range, 1000) or 1000
    return self:BFS(x, y, range, "BUSHES", false)
end

function MapLibrary:FindRiverCells(x, y, range)
    local range = range and min(range, 1000) or 1000
    return self:BFS(x, y, range, "RIVER", false)
end

function MapLibrary:FindWallCells(x, y, range)
    local range = range and min(range, 1000) or 1000
    return self:BFS(x, y, range, "WALLS", false)
end

-- Custom methods

function MapLibrary:GetHeight(x, y)
    if self.id == 0 then return -178.31 end
    if not self.heights then return 0.0 end
    local lx, ly = self.limitX, self.limitY
    local rx, ry = self:WorldToCell(x, y)
    if rx < 0 or ry < 0 or rx > lx or
        ry > ly then return 0.0 end
    return self.heights[rx][ry]
end

function MapLibrary:GetRegionName(x, y)
    local def = "UNDEFINED"
    if not self.regions then return def end
    local lx, ly = self.limitX, self.limitY
    local rx, ry = self:WorldToCell(x, y)
    if rx < 0 or ry < 0 or rx > lx or
        ry > ly then return def end
    local id = self.regions[rx][ry]
    return Regions[id] or def
end

-- Fast voxel traversal

function MapLibrary:VoxelTraversal(x1, y1, x2, y2, key)
    local is_found = function(cx, cy) return
        self.selector[key](cx, cy) == true end
    local sign = function(n) return n == 0 and 0
        or (n > 0 and 1 or n < 0 and -1 or 0) end
    local f0 = function(n) return n - floor(n) end
    local f1 = function(n) return 1 - n + floor(n) end
    local x1, y1 = self:_WorldToCell(x1, y1)
    local x2, y2 = self:_WorldToCell(x2, y2)
    local cx, cy = floor(x1), floor(y1)
    local lx, ly = floor(x2), floor(y2)
    if is_found(cx, cy) then return
        self:CellToWorld(cx, cy) end
    local dx, dy = (x2 - x1), (y2 - y1)
    local sx, sy = sign(dx), sign(dy)
    local tx = sx == 0 and huge or (sx / dx)
    local ty = sy == 0 and huge or (sy / dy)
    local mx = tx * (sx > 0 and f1 or f0)(x1)
    local my = ty * (sy > 0 and f1 or f0)(y1)
    local steps = abs(lx - cx) + abs(ly - cy)
    while steps >= 0 and (mx <= 1 or my <= 1) do
        local iter_step_x = mx < my and sx or 0
        local iter_step_y = mx >= my and sy or 0
        local iter_max_x = mx < my and tx or 0
        local iter_max_y = mx >= my and ty or 0
        if mx == my and is_found(cx + sx, cy) then
            return self:CellToWorld(cx + sx, cy) end
        cx, mx = cx + iter_step_x, mx + iter_max_x
        cy, my = cy + iter_step_y, my + iter_max_y
        if is_found(cx, cy) then return
            self:CellToWorld(cx, cy) end
        steps = steps - 1
    end
    return false
end

function MapLibrary:IntersectsBush(x1, y1, x2, y2)
    return self:VoxelTraversal(x1, y1, x2, y2, "BUSHES")
end

function MapLibrary:IntersectsRiver(x1, y1, x2, y2)
    return self:VoxelTraversal(x1, y1, x2, y2, "RIVER")
end

function MapLibrary:IntersectsWall(x1, y1, x2, y2)
    return self:VoxelTraversal(x1, y1, x2, y2, "WALLS")
end

-- Lookup methods

function MapLibrary:IsBush(x, y, skip)
    local bushes = self.bushes or {}
    if not self.map then return false end
    local lx, ly = self.limitX, self.limitY
    local rx, ry = self:WorldToCell(x, y, skip)
    if not skip and (rx < 0 or ry < 0 or rx >
        lx or ry > ly) then return false end
    if not bushes[rx] then return false end
    return bushes[rx][ry] ~= nil
end

function MapLibrary:IsRiver(x, y, skip)
    local river = self.river or {}
    if self.id == 0 then return false end
    if self.id == 5 then return false end
    if not self.map then return false end
    local lx, ly = self.limitX, self.limitY
    local rx, ry = self:WorldToCell(x, y, skip)
    if not skip and (rx < 0 or ry < 0 or rx >
        lx or ry > ly) then return false end
    if not river[rx] then return false end
    return river[rx][ry] ~= nil
end

function MapLibrary:IsWall(x, y, skip)
    local walls = self.walls or {}
    if not self.map then return false end
    local lx, ly = self.limitX, self.limitY
    local rx, ry = self:WorldToCell(x, y, skip)
    if not skip and (rx < 0 or ry < 0 or rx >
        lx or ry > ly) then return true end
    if not walls[rx] then return false end
    return walls[rx][ry] ~= nil
end

return MapLibrary:New()

